<script setup>
import { useGameStore } from '@/stores/game'
import { useRouter } from 'vue-router'

const store = useGameStore()
const router = useRouter()

function goToGame(levelId) {
  const level = store.currentLevels.find(l => l.id === levelId)
  if (!level.unlocked) {
    alert('此节点尚未解锁，请先完成前面的挑战！')
    return
  }
  router.push({
    path: `/game/${levelId}`,
    query: { year: store.year },
  })
}

function getNodeIcon(level) {
  if (level.completed) return 'fas fa-check'
  if (level.skipped) return 'fas fa-forward'
  if (level.unlocked) return 'fas fa-door-open'
  return 'fas fa-lock'
}
</script>

